mapper.select:
SELECT 
FROM "conversation"
WHERE "conversation_id" = #{conversationId}
  AND "creator_id" = #{userId}
  AND "deleted" = FALSE

SELECT FROM "conversation" c LEFT JOIN "conversation_group_relation" p ON p."conversation_id" = c."conversation_id" AND p."creator_id" = c."creator_id" AND p."conversation_group_id" IS NULL WHERE c."creator_id" = #{userId} AND c."deleted" = FALSE
AND c."title" ILIKE CONCAT('%', #{keyword}, '%')
ORDER BY CASE WHEN p."id" IS NULL THEN 1 ELSE 0 END ASC, p."sort_order" ASC NULLS LAST, c."modification_time" DESC, c."id" DESC LIMIT #{limit} OFFSET #{offset}

mapper.update:
UPDATE "conversation"
SET "deleted" = TRUE,
    "modifier_id" = #{userId},
    "modification_time" = NOW()
WHERE "creator_id" = #{userId}
  AND "deleted" = FALSE
  AND "conversation_id" IN (
      SELECT "conversation_id"
      FROM "conversation_group_relation"
      WHERE "creator_id" = #{userId}
        AND "conversation_group_id" = #{groupId}
  )

