SELECT NOT EXISTS ( SELECT 1 FROM ( VALUES
(#{conversationId})
) AS requested("conversation_id") WHERE NOT EXISTS ( SELECT 1 FROM "conversation" c WHERE c."creator_id" = #{userId} AND c."deleted" = FALSE AND c."conversation_id" = requested."conversation_id" ) )
